      "title": "The Concept of the Fault Loop",
      "basicQuestions": [
        {
          "questionText": "Where must fault current return to for the circuit to be complete?",
          "answerGuidance": [
            "Transformer",
            "The source",
            "The supply transformer"
          ],
          "hint": "Think of the starting point of the electricity supply.",
          "sourceTeachingPointIds": [
            "TP3"
          ]
        },
        {
          "questionText": "What is the technical term for the total resistance of the fault path in an AC system?",
          "answerGuidance": [
            "Impedance"
          ],
          "hint": "This term is used instead of 'resistance' in AC circuits.",
          "sourceTeachingPointIds": [
            "TP5"
          ]
        },
        {
          "questionText": "What happens to the fault current if the earth loop has very high resistance?",
          "answerGuidance": [
