        {
          "questionText": "In the term Ze, what does the letter 'e' stand for?",
          "answerGuidance": [
            "External"
          ],
          "hint": "It refers to the part of the loop outside the building.",
          "sourceTeachingPointIds": [
            "TP2"
          ]
        },
        {
          "questionText": "Which part of the earth loop is the electricity supplier responsible for?",
          "answerGuidance": [
            "Ze",
            "External impedance",
            "External earth fault loop impedance"
          ],
          "hint": "Use the technical term for the supply-side resistance.",
          "sourceTeachingPointIds": [
            "TP3"
          ]
        },
        {
          "questionText": "What part of the loop consists of the wiring specifically inside the building?",
          "answerGuidance": [
            "Internal part",
            "Internal wiring",
            "Consumer side"
          ],
          "hint": "This is the section the electrician installs and maintains.",
          "sourceTeachingPointIds": [
            "TP4"
          ]
        }
      ],
      "deeperQuestionText": "If an electrician measures a high total loop impedance but finds the building's internal wiring is perfect, which component is likely at fault?",
      "deeperAnswerGuidance": [
        "Ze",
        "External impedance",
        "The supplier's equipment",
        "The service cables or transformer"
      ],
      "deeperSourceTeachingPointIds": [
        "TP2",
        "TP3",
        "TP5"
      ],
      "hint": "Think about the two main sections that make up the total loop."
    },
    {
      "title": "Technical Components: Zs, Ze, R1, and R2",
      "basicQuestions": [
        {
          "questionText": "What is the symbol for the Total Earth Fault Loop Impedance of a circuit?",
          "answerGuidance": [
            "Zs"
          ],
          "hint": "It is the sum of all parts of the loop.",
          "sourceTeachingPointIds": [
            "TP1"
          ]
        },
        {
          "questionText": "What does the term R1 specifically refer to in the earth loop path?",
          "answerGuidance": [
            "Line conductor resistance",
            "Phase conductor resistance"
          ],
          "hint": "This is the resistance of the 'live' wire going to the fault.",
          "sourceTeachingPointIds": [
            "TP2"
          ]
        },
        {
          "questionText": "What does the term R2 specifically refer to in the earth loop path?",
          "answerGuidance": [
            "Circuit Protective Conductor resistance",
            "CPC resistance",
            "Earth wire resistance"
          ],
          "hint": "This is the resistance of the wire that carries fault current back from the equipment.",
          "sourceTeachingPointIds": [
            "TP3"
          ]
        }
      ],
      "deeperQuestionText": "How does the formula Zs = Ze + (R1 + R2) allow an electrician to verify the safety of a specific circuit?",
      "deeperAnswerGuidance": [
        "It calculates the total resistance the fault current will face",
        "It combines the supplier's impedance with the circuit's resistance",
        "It ensures the total impedance is low enough for the breaker to trip",
        "It accounts for every conductor in the fault path"
      ],
      "deeperSourceTeachingPointIds": [
        "TP4",
        "TP5"
      ],
      "hint": "Consider how adding these different resistances together relates to the operation of a fuse or breaker."
    },
    {
      "title": "Physical Path Components: MET and Supplier Return",
      "basicQuestions": [
        {
          "questionText": "What does the abbreviation MET stand for?",
          "answerGuidance": [
            "Main Earthing Terminal"
          ],
          "hint": "It is the central connection point for all earth wires.",
          "sourceTeachingPointIds": [
            "TP1"
          ]
        },
        {
          "questionText": "Which component acts as the central hub where all earthing and bonding conductors meet?",
          "answerGuidance": [
            "MET",
            "Main Earthing Terminal"
          ],
          "hint": "It is the bridge between the building and the supplier's earth.",
          "sourceTeachingPointIds": [
            "TP1",
            "TP2"
          ]
        },
        {
          "questionText": "What is the name of the physical route that carries current from the MET back to the transformer?",
          "answerGuidance": [
            "Supplier earth return path"
          ],
          "hint": "This is the final leg of the journey outside the building.",
          "sourceTeachingPointIds": [
            "TP3"
          ]
        }
      ],
      "deeperQuestionText": "Why is a failure at the Main Earthing Terminal (MET) considered a critical safety risk for the entire installation?",
      "deeperAnswerGuidance": [
        "It is the single point of connection for the earthing system",
        "It disconnects the internal earth wires from the return path",
        "It breaks the loop for every circuit in the building",
        "Fault current cannot return to the transformer if this link is broken"
      ],
      "deeperSourceTeachingPointIds": [
        "TP2",
        "TP5"
      ],
      "hint": "Think about what happens to the 'loop' if the central hub connecting the house to the supplier is removed."
    }
  ]
}

